import { getConnection } from "../config/db.js";
import sql from "mssql";

// ✅ Obtener todos los productos
export const obtenerProductos = async (req, res) => {
  try {
    const pool = await getConnection();
    const result = await pool.request().query("SELECT * FROM Productos");
    res.json(result.recordset);
  } catch (error) {
    console.error("❌ Error al obtener productos:", error);
    res.status(500).json({ message: "Error al obtener productos" });
  }
};

// ✅ Crear producto
export const crearProducto = async (req, res) => {
  try {
    const { Nombre, Descripcion, Precio, Stock } = req.body;
    const pool = await getConnection();

    await pool
      .request()
      .input("Nombre", sql.NVarChar, Nombre)
      .input("Descripcion", sql.NVarChar, Descripcion)
      .input("Precio", sql.Decimal(10, 2), Precio)
      .input("Stock", sql.Int, Stock)
      .query(
        "INSERT INTO Productos (Nombre, Descripcion, Precio, Stock) VALUES (@Nombre, @Descripcion, @Precio, @Stock)"
      );

    res.status(201).json({ message: "✅ Producto agregado correctamente" });
  } catch (error) {
    console.error("❌ Error al crear producto:", error);
    res.status(500).json({ message: "Error al crear producto" });
  }
};

// ✅ Actualizar producto
export const actualizarProducto = async (req, res) => {
  try {
    const { ProductoID } = req.params;
    const { Nombre, Descripcion, Precio, Stock } = req.body;
    const pool = await getConnection();

    await pool
      .request()
      .input("ProductoID", sql.Int, ProductoID)
      .input("Nombre", sql.NVarChar, Nombre)
      .input("Descripcion", sql.NVarChar, Descripcion)
      .input("Precio", sql.Decimal(10, 2), Precio)
      .input("Stock", sql.Int, Stock)
      .query(
        "UPDATE Productos SET Nombre=@Nombre, Descripcion=@Descripcion, Precio=@Precio, Stock=@Stock WHERE ProductoID=@ProductoID"
      );

    res.json({ message: "✅ Producto actualizado correctamente" });
  } catch (error) {
    console.error("❌ Error al actualizar producto:", error);
    res.status(500).json({ message: "Error al actualizar producto" });
  }
};

// ✅ Eliminar producto
export const eliminarProducto = async (req, res) => {
  try {
    const { ProductoID } = req.params;
    const pool = await getConnection();

    await pool
      .request()
      .input("ProductoID", sql.Int, ProductoID)
      .query("DELETE FROM Productos WHERE ProductoID = @ProductoID");

    res.json({ message: "🗑️ Producto eliminado correctamente" });
  } catch (error) {
    console.error("❌ Error al eliminar producto:", error);
    res.status(500).json({ message: "Error al eliminar producto" });
  }
};
